import java.util.List;
import java.util.ArrayList;
import sailpoint.object.Identity;
import sailpoint.object.WorkItem;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import sailpoint.tools.Util;
import java.util.Iterator;
import java.util.HashMap;
import java.util.Date;

try{
    QueryOptions queryOptions = new QueryOptions();
    String idName = form.getField("manager")!=null ? form.getField("manager").getValue() : null;
    Identity managerId = context.getObjectByName(Identity.class, idName);
    List desList = new ArrayList();
    Filter workitemFilter =  Filter.and(Filter.eq("owner", managerId),Filter.eq("type","Certification"));
    queryOptions.addFilter(workitemFilter);
    List workitesmList = context.getObjects(WorkItem.class, queryOptions);               
    for(WorkItem wi : workitesmList){
      Date expDate = wi.getExpirationDate();
      Date currentDate = new Date();
      if (expDate.after(currentDate)) {
        desList.add(wi.getDescription()+"###"+wi.getId());  
      }                  
    }
return desList;
}catch(Exception e) {
    error("ASCN.Form.ReassignWorkitems", "Exception encountered in ASCN-ReassignWorkitems Form: ",e);
}

 
boolean result=false;
String idName = form.getField("manager")!=null ? form.getField("manager").getValue() : null;
if(idName==null || idName.isEmpty() ){
    result=true;
}
return result;
